}

function deepClone(obj) {
  return JSON.parse(JSON.stringify(obj));
}

function logBatch(messages) {
  let output = "";
  for (const msg of messages) {
    output += `[${new Date().toISOString()}] ${msg}\n`;
  }
  fs.writeFileSync("/var/log/app.log", output);
}

